mapper.insert:
INSERT INTO daily_sales_summary (stat_date, total_revenue, order_count, visit_count, avg_usage_time) SELECT #{targetDate}, /* 1. payment 테이블의 실제 결제 완료 금액(DONE) 합계 */ IFNULL(SUM(p.final_amount), 0),
/* 2. 해당 날짜에 결제 완료된 세션에 포함된 모든 주문 건수 */ (SELECT COUNT(*) FROM orders o JOIN payment p2 ON o.session_id = p2.session_id WHERE p2.status = 'DONE' AND p2.paid_at >= #{targetDate} AND p2.paid_at < DATE_ADD(#{targetDate}, INTERVAL 1 DAY)),
/* 3. 방문자 수: 세션 초기 인원 + 추가 인원(GUEST 카테고리) 수량 */ IFNULL(SUM(ts.initial_guest_cnt + IFNULL(extra.extra_qty, 0)), 0),
/* 4. 평균 이용 시간 */ IFNULL(AVG(TIMESTAMPDIFF(MINUTE, ts.check_in_time, ts.check_out_time)), 0) FROM payment p INNER JOIN table_session ts ON p.session_id = ts.id LEFT JOIN ( /* GUEST 카테고리(인원 추가) 수량 미리 합산 */ SELECT o.session_id, SUM(oi.quantity) as extra_qty FROM order_item oi INNER JOIN orders o ON oi.order_id = o.id INNER JOIN menu m ON oi.menu_id = m.id INNER JOIN category c ON m.category_id = c.id WHERE c.type = 'GUEST' AND o.status = 'COMPLETED' GROUP BY o.session_id ) extra ON p.session_id = extra.session_id WHERE p.status = 'DONE' AND p.paid_at >= #{targetDate} AND p.paid_at < DATE_ADD(#{targetDate}, INTERVAL 1 DAY) ON DUPLICATE KEY UPDATE total_revenue = VALUES(total_revenue), order_count = VALUES(order_count), visit_count = VALUES(visit_count), avg_usage_time = VALUES(avg_usage_time)
